const req = $input.first().json;
if (req.action === 'loadPreviousSession') {
  const H = (c) => ({ type: 'constructor', id: ['langchain_core', 'messages', 'HumanMessage'], kwargs: { content: c } });
  const A = (c) => ({ type: 'constructor', id: ['langchain_core', 'messages', 'AIMessage'], kwargs: { content: c } });
  return [{ json: { data: [
    H('turn one question'), A('turn one answer'),
    H('turn two question'), A('turn two answer'),
    H('turn three question'), A('turn three answer'),
  ] } }];
}
return [{ json: { output: JSON.stringify(req) } }];
